def activity(
    slug: str,
    title: str,
    description: str,
    steps: list[str],
    duration: int,
    difficulty: int,
    materials: str,
    domains: list[str],
    ages: list[str],
    tags: list[str],
    safety: str | None = None,
) -> dict:
    item = {
        "remote_id": f"catalog-{slug}",
        "version": 1,
        "updated_at": UPDATED_AT,
        "title": title,
        "short_desc": description,
        "instruction": "\n".join(
            f"{index}) {step}" for index, step in enumerate(steps, start=1)
        ),
        "duration_min": duration,
        "difficulty": difficulty,
        "materials": materials,
        "domains": domains,
        "age_groups": ages,
        "tags": tags,
    }
    if safety:
        item["safety_notes"] = safety
    return item


