def main() -> None:
    payload = json.loads(CONTENT_PATH.read_text(encoding="utf-8"))
    payload["content_version"] = "2026.06.15.1"
    payload["etag"] = "preschool-content-2026-06-15-1"
    payload["domains"] = [
        {"name": name, "description": description}
        for name, description in DOMAINS.items()
    ]
    payload["age_groups"] = AGE_GROUPS

    activities = {
        item["remote_id"]: item for item in payload.get("activities", [])
    }
    activities.update({item["remote_id"]: item for item in NEW_ACTIVITIES})
    payload["activities"] = list(activities.values())

    CONTENT_PATH.write_text(
        json.dumps(payload, ensure_ascii=False, indent=2) + "\n",
        encoding="utf-8",
    )


if __name__ == "__main__":
    main()
